async function getUser(id) {
  const key = `user:${id}`;
  const cached = await redis.get(key);
  if (cached) return JSON.parse(cached);

  const user = await db.user.findById(id);
  await redis.setex(key, 300, JSON.stringify(user)); // 5-min TTL
  return user;
}

// Sliding window with Redis sorted sets
async function isRateLimited(ip, limit = 100, windowMs = 60000) {
  const now  = Date.now();
  const key  = `rl:${ip}`;
  const pipe = redis.pipeline();
  pipe.zremrangebyscore(key, 0, now - windowMs); // evict old
  pipe.zadd(key, now, now.toString());            // add current
  pipe.zcard(key);                                // count window
  pipe.expire(key, 60);
  const results = await pipe.exec();
  return results[2][1] > limit;
}

